(()=>{const $=(r,s)=>r.querySelector(s),n=(r,s)=>Number($(r,s)?.value||0);function run(r){const m=r.dataset.calcMode,a=n(r,'[data-a]'),b=n(r,'[data-b]'),c=n(r,'[data-c]'),d=n(r,'[data-d]')||1;let out='';if(m==='percentage')out=`${a}% of ${b} = ${a*b/100}\n${a} is ${(a/b*100||0).toFixed(2)}% of ${b}`;else if(m==='change')out=`Change: ${b-a}\nPercentage change: ${((b-a)/a*100||0).toFixed(2)}%`;else if(m==='discount'){const saved=a*b/100,subtotal=a-saved,tax=subtotal*c/100;out=`Original: ${a}\nDiscount: ${b}%\nSaved: ${saved.toFixed(2)}\nSubtotal: ${subtotal.toFixed(2)}\nTax: ${tax.toFixed(2)}\nFinal: ${(subtotal+tax).toFixed(2)}`;}else if(m==='margin'){const profit=a-b;out=`Revenue: ${a}\nCost: ${b}\nProfit: ${profit.toFixed(2)}\nMargin: ${(profit/a*100||0).toFixed(2)}%\nMarkup: ${(profit/b*100||0).toFixed(2)}%`;}else if(m==='compound'){const total=a*Math.pow(1+(b/100)/d,d*c);out=`Final amount: ${total.toFixed(2)}\nInterest earned: ${(total-a).toFixed(2)}\nPrincipal: ${a}\nRate: ${b}%\nYears: ${c}\nCompounds/year: ${d}`;}$(r,'[data-calc-output]').value=out;$(r,'[data-stats]').innerHTML=`<div><strong>${(out.match(/[-+]?[0-9]*\.?[0-9]+/g)||[])[0]||0}</strong><span>Primary result</span></div>`;$(r,'[data-status]').textContent='Calculated.';}document.addEventListener('click',e=>{const r=e.target.closest('.calc-core-tool');if(!r)return;if(e.target.matches('[data-calc-run]'))run(r);if(e.target.matches('[data-calc-copy]'))navigator.clipboard.writeText($(r,'[data-calc-output]').value);if(e.target.matches('[data-calc-clear]')){r.querySelectorAll('input').forEach(x=>x.value='');$(r,'[data-calc-output]').value='';$(r,'[data-stats]').innerHTML='';}});document.addEventListener('input',e=>{const r=e.target.closest('.calc-core-tool');if(r)run(r)});})();